10	function parseArgs(argv) {
11	  const out = { _: [] };
12	  for (let i = 0; i < argv.length; i++) {
13	    const a = argv[i];
14	    if (a.startsWith('--')) {
15	      const key = a.slice(2);
16	      const next = argv[i + 1];
17	      if (next && !next.startsWith('--')) {
18	        out[key] = next;
19	        i++;
20	      } else {
21	        out[key] = true;
22	      }
23	    } else {
24	      out._.push(a);
25	    }
26	  }
27	  return out;
28	}
