328	    if (r.pulled && r.pulled.imported === false) {
329	      console.log(`PI 게이트: 제외 선택 → 기준(${r.pulled.from})을 가져오지 않아 동기화 중단.`);
330	      return;
331	    }
332	    console.log(`✓ pull: ${r.pulled.from} → canonical` + (r.pulled.piHandled ? ` (PI:${r.pulled.piHandled})` : ''));
333	    if (r.pulled.unofficialSource) console.log('  ⚠ 비공식 위치에서 가져왔습니다.');
334	    console.log('push 결과:');
335	    for (const x of r.results) {
336	      if (x.action === 'pushed') {
337	        console.log(`  ${x.tool}: 적용 → ${x.targetPath}` + (x.backup ? `  (백업 ${x.backup})` : '  (신규라 백업 없음)'));
338	        for (const l of x.losses || []) console.log('     ⚠ 손실: ' + l);
339	      } else if (x.action === 'skipped_same') {
340	        console.log(`  ${x.tool}: skip (내용 동일)`);
341	      } else if (x.action === 'error') {
342	        console.log(`  ${x.tool}: ✗ 오류 — ${x.error}`);
