//  모든 쓰기는 기존 skillPull/agentPull/skillPush/agentPush 경유.
//  PI 감지 시 pull이 PiGateError를 던지며, 여기서 잡지 않고 그대로 전파(서버 409).
function syncApply({ kind, name, baseTool, sourceId, piAck }) {
  if (kind !== 'skill' && kind !== 'agent') throw new Error("알 수 없는 kind: " + kind + " ('skill'|'agent')");
  if (!name) throw new Error('name이 필요합니다');
  if (!paths.TOOLS.includes(baseTool)) throw new Error('기준 도구가 올바르지 않습니다(baseTool): ' + baseTool);

  const plan = syncPlan({ kind, name });
  const baseSlot = plan.tools.find((t) => t.tool === baseTool);
  if (!baseSlot || !baseSlot.exists) {
    throw new Error(`기준 도구(${baseTool})에 ${kind} "${name}"가 없습니다. baseCandidates: [${plan.baseCandidates.join(', ')}]`);
  }

  // 1) pull: 기준 도구 → canonical (기존 함수 재사용 — PI 게이트/gitCommit 상속)
  let pulled;
  if (kind === 'skill') {
    const r = skillPull({ name, source_id: sourceId || SKILL_TOOL_SOURCE[baseTool], piAck });
    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
    pulled = { from: baseTool, kind: 'skill', name, source_tool: r.skill.source_tool, unofficialSource: r.unofficialSource, piHandled: r.piHandled };
  } else {
    const r = agentPull({ from: baseTool, name, piAck });
    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
    pulled = { from: baseTool, kind: 'agent', id: r.agent.id, source_tool: r.agent.source_tool, piHandled: r.piHandled };
  }

  // pull 이후의 canonical 내용으로 나머지 도구와 비교(기준 자신은 skip).
  const results = [];
  for (const tool of paths.TOOLS) {
    if (tool === baseTool) continue;
    try {
      const preview = kind === 'skill'
        ? skillPush({ name, to: tool, apply: false })
        : agentPush({ id: 'agent-' + name, to: tool, apply: false });
      if (!preview.hasChanges) {
        // canonical과 내용 동일(대상이 이미 존재하고 같음) → skip
        results.push({ tool, action: 'skipped_same', targetPath: preview.targetPath, losses: preview.losses });
        continue;
      }
      const applied = kind === 'skill'
        ? skillPush({ name, to: tool, apply: true })
        : agentPush({ id: 'agent-' + name, to: tool, apply: true });
      results.push({ tool, action: 'pushed', targetPath: applied.targetPath, backup: applied.backupPath, losses: applied.losses });
    } catch (e) {
      // 부분 실패: 중단하지 말고 도구별 결과로 기록.
      results.push({ tool, action: 'error', error: e.message });
    }
  }
  return { pulled, results };
}

