'use strict';
// 격리 검증 스크립트 — 실제 홈/canonical/backups 무변경. 모두 AAD_* 오버라이드로 격리.
const fs = require('fs');
const path = require('path');
const core = require('/Users/won-yechan/miru_github/agent-dashboard/cli/core.js');
const mode = require('/Users/won-yechan/miru_github/agent-dashboard/cli/mode.js');

const PROJ = process.env.PROJ;
const HOME = process.env.AAD_FIXTURES;
function line(x) { console.log(x); }
function exists(p) { return fs.existsSync(p); }

line('== mode: ' + mode.getMode() + ' realAllowed=' + mode.realAllowed());

// register project
const add = core.projectsAdd({ root: PROJ });
line('projectsAdd: added=' + add.added + ' root=' + (add.project ? add.project.root : add.root));

// snapshot global home skill mtime + codex project dir non-existence BEFORE
const globalSkill = path.join(HOME, 'claude', 'skills', '01-acm-flow', 'SKILL.md');
const globalBodyBefore = fs.readFileSync(globalSkill, 'utf8');
const projCodexSkill = path.join(PROJ, '.agents', 'skills', '01-acm-flow', 'SKILL.md');
line('BEFORE: global skill exists=' + exists(globalSkill) + ' | proj codex(.agents) skill exists=' + exists(projCodexSkill));

// ---------- ① syncPlan(scope=proj) ----------
line('\n--- (1) skillSyncPlan scope=PROJECT ---');
const planP = core.syncPlan({ kind: 'skill', name: '01-acm-flow', scope: PROJ });
line('scope=' + planP.scope + ' baseCandidates=' + JSON.stringify(planP.baseCandidates));
for (const t of planP.tools) {
  line('  tool=' + t.tool + ' exists=' + t.exists + ' sourceId=' + t.sourceId + ' notes=' + JSON.stringify(t.notes));
}

// ---------- ④ notes must NOT include own-scope file ----------
const claudeSlot = planP.tools.find((t) => t.tool === 'claude');
const ownPath = path.join(PROJ, '.claude', 'skills', '01-acm-flow', 'SKILL.md');
const notesMentionSelf = (claudeSlot.notes || []).some((n) => n.includes(ownPath));
line('(4) claude slot notes mention OWN project file? ' + notesMentionSelf + ' (expect false)');
const notesMentionGlobal = (claudeSlot.notes || []).some((n) => n.includes(globalSkill));
line('    claude slot notes mention GLOBAL file (other location)? ' + notesMentionGlobal + ' (expect true)');

// ---------- ② syncApply(scope=proj, baseTool=claude) ----------
line('\n--- (2) skill syncApply scope=PROJECT base=claude ---');
const applyP = core.syncApply({ kind: 'skill', name: '01-acm-flow', baseTool: 'claude', scope: PROJ });
line('result.scope=' + applyP.scope);
for (const r of applyP.results) line('  push ' + r.tool + ' action=' + r.action + ' target=' + r.targetPath);
line('AFTER apply: proj codex(.agents) skill exists=' + exists(projCodexSkill) + ' (expect true)');
// global home must be UNCHANGED
const globalBodyAfter = fs.readFileSync(globalSkill, 'utf8');
line('global home skill UNCHANGED? ' + (globalBodyBefore === globalBodyAfter) + ' (expect true)');
// canonical + backups isolation
line('canonical root = ' + require('/Users/won-yechan/miru_github/agent-dashboard/cli/paths.js').canonicalRoot());
line('backups root   = ' + require('/Users/won-yechan/miru_github/agent-dashboard/cli/paths.js').backupRoot());

// ---------- ③ regression: scope omitted (global) ----------
line('\n--- (3) REGRESSION scope omitted (global) ---');
const planG = core.syncPlan({ kind: 'skill', name: '01-acm-flow' });
line('scope=' + planG.scope + ' baseCandidates=' + JSON.stringify(planG.baseCandidates));
const claudeG = planG.tools.find((t) => t.tool === 'claude');
line('global claude slot: exists=' + claudeG.exists + ' sourceId=' + claudeG.sourceId + ' notes=' + JSON.stringify(claudeG.notes));
// global apply target should be the GLOBAL codex .agents/skills (fixtures), not project
const applyG = core.syncApply({ kind: 'skill', name: '01-acm-flow', baseTool: 'claude' }); // no scope
line('global apply scope=' + applyG.scope);
for (const r of applyG.results) line('  push ' + r.tool + ' action=' + r.action + ' target=' + r.targetPath);
const globalCodexSkill = path.join(HOME, 'agents', 'skills', '01-acm-flow', 'SKILL.md');
line('global codex target written under fixtures home? ' + exists(globalCodexSkill) + ' (expect true)');

// ---------- unregistered project rejection ----------
line('\n--- (5) unregistered scope rejected ---');
try {
  core.syncApply({ kind: 'skill', name: '01-acm-flow', baseTool: 'claude', scope: '/tmp/not-registered-xyz' });
  line('ERROR: unregistered scope was accepted (should have thrown)');
} catch (e) {
  line('unregistered scope rejected OK: ' + e.message);
}

line('\nDONE');

